import{_ as r,o as e,c as a,ae as d}from"./chunks/framework.DrYEjkpc.js";const g=JSON.parse('{"title":"Skill 优化（Optimization）","description":"","frontmatter":{},"headers":[],"relativePath":"radar/category-05-optimization.md","filePath":"radar/category-05-optimization.md"}'),o={name:"radar/category-05-optimization.md"};function l(i,t,n,s,h,c){return e(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="skill-优化-optimization" tabindex="-1">Skill 优化（Optimization） <a class="header-anchor" href="#skill-优化-optimization" aria-label="Permalink to &quot;Skill 优化（Optimization）&quot;">​</a></h1><blockquote><p><strong>成熟度</strong>: 🟡 成长期 · <strong>综合评分</strong>: <strong>0.59</strong></p><p><strong>业界判断</strong>：<strong>8 个进化框架（含 SkillRL）+ SkillReducer Token 优化</strong>，<strong>技术路径最丰富</strong>，但各自为政缺标准。<strong>没有任何进化框架在循环中加入安全扫描</strong>。</p></blockquote><hr><h2 id="业界代表产品" tabindex="-1">业界代表产品 <a class="header-anchor" href="#业界代表产品" aria-label="Permalink to &quot;业界代表产品&quot;">​</a></h2><table tabindex="0"><thead><tr><th>产品</th><th>来源</th><th>进化信号</th><th>关键数字</th></tr></thead><tbody><tr><td><a href="./tech-openspace.html">OpenSpace</a></td><td>HKU (<strong>6.1K+ ★</strong>)</td><td>FIX / DERIVED / CAPTURED 三模式</td><td>220 任务 40.8% → 70.8%, Token -46%</td></tr><tr><td><a href="./tech-hermes-self-evolution.html">Hermes Self-Evolution</a></td><td>Nous Research (3.1K+ ★)</td><td>GEPA 优化器 + PR 审核</td><td>ICLR 2026 接收</td></tr><tr><td><a href="./tech-skillclaw.html">SkillClaw</a></td><td>AMAP-ML (1.3K+ ★)</td><td>多用户轨迹聚合</td><td>Qwen3-Max 验证</td></tr><tr><td><a href="./tech-metaclaw.html">MetaClaw</a></td><td>OpenClaw (3.4K+ ★)</td><td>Fast Loop + Slow Loop 双环</td><td>Kimi-K2.5 21.4% → 40.6%</td></tr><tr><td><a href="./tech-skillreducer.html">SkillReducer</a></td><td>港科大</td><td>静态压缩 + 渐进披露</td><td><strong>600 Skill + SkillsBench，压缩后 +2.8%</strong></td></tr><tr><td><a href="./tech-evoskill.html">EvoSkill (Pareto)</a></td><td>Sentient AGI (726 ★)</td><td>Pareto 前沿 + Git 分支</td><td>+7.3% OfficeQA / +12.1% SealQA</td></tr><tr><td><a href="./tech-skillforge.html">SkillForge (Optimizer)</a></td><td>工业研究 (SIGIR 2026)</td><td>三阶段失败归因</td><td>1,883 工单 + 5 场景</td></tr><tr><td><a href="./tech-skillrl.html">SkillRL</a></td><td>aiming-lab</td><td>Skill 库随 RL 策略递归共进化</td><td>+15.3% ALFWorld / WebShop</td></tr></tbody></table><hr><h2 id="进化信号源对比" tabindex="-1">进化信号源对比 <a class="header-anchor" href="#进化信号源对比" aria-label="Permalink to &quot;进化信号源对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>信号源</th><th>代表产品</th><th>优势</th><th>局限</th></tr></thead><tbody><tr><td>失败轨迹分析</td><td>EvoSkill / SkillForge</td><td>直接针对痛点改进</td><td>依赖 ground-truth</td></tr><tr><td>协同进化验证</td><td>EvoSkills</td><td>不完全依赖 ground-truth</td><td>仍需 oracle 最终裁决</td></tr><tr><td>并行轨迹池蒸馏</td><td>Trace2Skill</td><td>整体分析避免过拟合</td><td>需要大量并行轨迹</td></tr><tr><td>多用户集体经验</td><td>SkillClaw</td><td>一人发现全员受益</td><td>隐私和冲突解决未详述</td></tr><tr><td>双环架构（Skill + 权重）</td><td>MetaClaw</td><td>零停机 + 同时进化</td><td>绑定 OpenClaw + 需模型权限</td></tr><tr><td>DSPy + GEPA 优化</td><td>Hermes</td><td>理解&quot;为什么失败&quot;</td><td>绑定 Hermes + PR 需人审</td></tr><tr><td>三模式实时进化</td><td>OpenSpace</td><td>覆盖最广</td><td>长期稳定性未验证</td></tr><tr><td>RL 共进化</td><td>SkillRL</td><td>Skill 库与策略一起学习</td><td>需要可定义 reward</td></tr></tbody></table><hr><h2 id="行业核心痛点" tabindex="-1">行业核心痛点 <a class="header-anchor" href="#行业核心痛点" aria-label="Permalink to &quot;行业核心痛点&quot;">​</a></h2><h3 id="🟡-三方归因纠缠" tabindex="-1">🟡 三方归因纠缠 <a class="header-anchor" href="#🟡-三方归因纠缠" aria-label="Permalink to &quot;🟡 三方归因纠缠&quot;">​</a></h3><p>知道 Skill 效果不好，但<strong>不知道该改 Skill 内容、换底层模型还是修路由逻辑</strong> —— 像网站加载慢可能是服务器、网络或前端代码，但没有工具帮你定位。</p><p>所有方案都只回答&quot;是否 Skill 的问题&quot;，<strong>不区分模型能力和路由错误的贡献</strong>。</p><h3 id="🟡-跷跷板效应" tabindex="-1">🟡 跷跷板效应 <a class="header-anchor" href="#🟡-跷跷板效应" aria-label="Permalink to &quot;🟡 跷跷板效应&quot;">​</a></h3><p>改好了一个 Skill 结果另一个场景变差。EvoSkill Pareto 前沿是最接近的缓解机制，但<strong>没有论文在 Skill 场景下系统量化跷跷板效应</strong>。</p><h3 id="🟡-用户间经验不传播" tabindex="-1">🟡 用户间经验不传播 <a class="header-anchor" href="#🟡-用户间经验不传播" aria-label="Permalink to &quot;🟡 用户间经验不传播&quot;">​</a></h3><p>A 项目踩的坑，B 项目同事又踩一遍。SkillClaw / OpenSpace / MetaClaw 解决了一部分，但<strong>隐私 / 冲突 / 跨生态</strong>问题未根本解决。</p><h3 id="🟡-token-浪费-注意力稀释-less-is-more-效应" tabindex="-1">🟡 Token 浪费 + 注意力稀释（less-is-more 效应） <a class="header-anchor" href="#🟡-token-浪费-注意力稀释-less-is-more-效应" aria-label="Permalink to &quot;🟡 Token 浪费 + 注意力稀释（less-is-more 效应）&quot;">​</a></h3><p>SkillReducer 实证（600 Skill + SkillsBench）：<strong>26.4% Skill 没写 description、60%+ body 是非可操作内容</strong>。压缩后质量反升 2.8% —— 干扰 Agent 注意力的噪音少了。但仅静态压缩，<strong>未做动态按需加载</strong>。</p><h3 id="🚨-进化-安全的交叉空白" tabindex="-1">🚨 进化 + 安全的交叉空白 <a class="header-anchor" href="#🚨-进化-安全的交叉空白" aria-label="Permalink to &quot;🚨 进化 + 安全的交叉空白&quot;">​</a></h3><blockquote><p>8 个进化框架都在自动生成新 Skill，<strong>没有一个在进化循环中检查&quot;进化出来的 Skill 是否安全&quot;</strong>。进化可能无意中引入漏洞 —— 比如&quot;更高效&quot;的 Skill 通过跳过权限检查实现高效。</p></blockquote><p>Hermes 约束门控能拦截功能退化，但<strong>测试套件不包含安全检查</strong>。</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><blockquote><p>这些框架正在<strong>趋同</strong> —— 都在走向&quot;执行 → 分析 → 进化 → 验证 → 部署&quot;的闭环。差异化空间不在&quot;是否做进化&quot;（everyone does），而在三个维度：</p><ol><li><strong>进化信号的质量</strong>（粗粒度 pass/fail vs 精细过程反馈）</li><li><strong>安全门控</strong>（约束门控 vs 自动修复，哪种更可靠？）</li><li><strong>跨平台可移植性</strong>（Agent-agnostic vs 平台绑定）</li></ol></blockquote>',25)])])}const p=r(o,[["render",l]]);export{g as __pageData,p as default};
